module top_module(in1,
            in2,
            out,
            clk,
            rst);input [3:0]in1,in2;
    input rst,clk;

    output reg [4:0] out;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge rst or posedge dbg_halt)
    begin
        if(rst==1)
        begin
            out<=0;
        end
        else 
        begin
            out<=in1+in2;    
        end
    end

endmodule
